import{_ as a,o,c as t,ag as d}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"ADR-0003: Band Model","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/10_governance/50_decisions/adr-0003_band_model.md","filePath":"10_core/10_governance/50_decisions/adr-0003_band_model.md"}'),n={name:"10_core/10_governance/50_decisions/adr-0003_band_model.md"};function c(r,e,s,i,l,h){return o(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="adr-0003-band-model" tabindex="-1">ADR-0003: Band Model <a class="header-anchor" href="#adr-0003-band-model" aria-label="Permalink to &quot;ADR-0003: Band Model&quot;">​</a></h1><p><strong>Date</strong>: 2026-03-27 <strong>Status</strong>: Accepted</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>As the number of schemas grew, it became unclear which components depended on which. There was no formal structural tier model to describe the dependency hierarchy between system infrastructure, platform services, and business domains.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>QiOS adopts a <strong>3-band structural model</strong>:</p><table tabindex="0"><thead><tr><th>Band</th><th>ID</th><th>Schemas</th></tr></thead><tbody><tr><td>Core</td><td><code>b_core</code></td><td><code>qiarchive</code>, <code>qigraph</code>, <code>qially</code>, <code>qisys</code></td></tr><tr><td>Platform</td><td><code>b_platform</code></td><td><code>qione</code>, <code>public</code></td></tr><tr><td>Domain</td><td><code>b_domain</code></td><td><code>qicase</code>, <code>qichronicle</code>, <code>qicms</code>, <code>qihome</code>, <code>qiknowledge</code>, <code>qitax</code>, <code>qivault</code></td></tr></tbody></table><p>Dependency direction:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Domain → Platform → Core</span></span></code></pre></div><p>No band may create a dependency in the reverse direction.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li>Every new schema must be assigned a band in <code>registry/band_registry.yaml</code></li><li>Core schemas must not reference Domain schemas</li><li>The <code>enforce_structure.py</code> script validates band assignments on every PR</li></ul>',12)])])}const _=a(n,[["render",c]]);export{p as __pageData,_ as default};
